import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Phase, Task } from '../../core/models';


interface Row {
  id: string;
  name: string;
  phaseColorVar: string;
  x: number; y: number; w: number; h: number;
  progW: number;
  progressPct: number;
  startsOn: string; endsOn: string;
}
interface Arrow { id: string; d: string; }
interface Tick { x: number; label: string; }

const DAY = 86400000;

/**
 * SiteView schedule (Gantt) — hand-rolled inline SVG. A date→x scale spans the
 * project timeline; one row per task with a bar rect + inner progress-fill rect
 * (width ∝ progressPct). Dependency links render as SVG elbow paths with an
 * arrowhead marker. Planners drag along a bar to set progress; viewers are
 * read-only.
 *
 * DATA CONTRACT: `tasks` / `phases` are signal<T[]> of mock data; the
 * service_agent stage clears them and wires ApiService.listTasks()/listPhases()
 * in ngOnInit, and PATCH /tasks/:id/progress on drop.
 */
@Component({
  selector: 'app-gantt',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './gantt.component.html',
  styleUrl: './gantt.component.css',
})
export class GanttComponent implements OnInit {
  readonly projectId = signal<string>('');

  readonly phases = signal<Phase[]>([
    { id: 'ph1', projectId: 'p1', name: 'Site Prep & Foundation', order: 1 },
    { id: 'ph2', projectId: 'p1', name: 'Structure & Envelope', order: 2 },
    { id: 'ph3', projectId: 'p1', name: 'Interior & Fit-out', order: 3 },
  ]);

  readonly tasks = signal<Task[]>([
    { id: 't1', phaseId: 'ph1', name: 'Site clearing', startsOn: '2026-03-02', endsOn: '2026-03-13', progressPct: 100, dependsOnTaskId: null },
    { id: 't2', phaseId: 'ph1', name: 'Excavation', startsOn: '2026-03-16', endsOn: '2026-03-27', progressPct: 100, dependsOnTaskId: 't1' },
    { id: 't3', phaseId: 'ph1', name: 'Foundation pour', startsOn: '2026-03-30', endsOn: '2026-04-17', progressPct: 70, dependsOnTaskId: 't2' },
    { id: 't4', phaseId: 'ph2', name: 'Steel frame erection', startsOn: '2026-04-20', endsOn: '2026-05-15', progressPct: 40, dependsOnTaskId: 't3' },
    { id: 't5', phaseId: 'ph2', name: 'Roofing', startsOn: '2026-05-18', endsOn: '2026-06-05', progressPct: 10, dependsOnTaskId: 't4' },
    { id: 't6', phaseId: 'ph2', name: 'Exterior cladding', startsOn: '2026-05-25', endsOn: '2026-06-19', progressPct: 5, dependsOnTaskId: 't4' },
    { id: 't7', phaseId: 'ph3', name: 'MEP rough-in', startsOn: '2026-06-08', endsOn: '2026-06-26', progressPct: 0, dependsOnTaskId: 't5' },
    { id: 't8', phaseId: 'ph3', name: 'Interior finishes', startsOn: '2026-06-29', endsOn: '2026-07-24', progressPct: 0, dependsOnTaskId: 't7' },
  ]);

  // Geometry constants.
  readonly labelW = 156;
  readonly headerH = 34;
  readonly rowH = 46;
  readonly barH = 24;
  readonly pxPerDay = 7;

  private dragId: string | null = null;

  private readonly phaseColors = ['var(--color-phase-a)', 'var(--color-phase-b)', 'var(--color-phase-c)'];

  private day(iso: string): number { return Math.floor(Date.parse(iso) / DAY); }

  readonly minDay = computed(() => Math.min(...this.tasks().map((t) => this.day(t.startsOn))));
  readonly maxDay = computed(() => Math.max(...this.tasks().map((t) => this.day(t.endsOn))));

  readonly width = computed(() => this.labelW + (this.maxDay() - this.minDay() + 2) * this.pxPerDay + 24);
  readonly height = computed(() => this.headerH + this.tasks().length * this.rowH + 8);

  private phaseColorFor(phaseId: string): string {
    const idx = this.phases().findIndex((p) => p.id === phaseId);
    return this.phaseColors[idx % this.phaseColors.length];
  }

  readonly rows = computed<Row[]>(() => {
    const min = this.minDay();
    return this.tasks().map((t, i) => {
      const x = this.labelW + (this.day(t.startsOn) - min) * this.pxPerDay;
      const w = Math.max((this.day(t.endsOn) - this.day(t.startsOn) + 1) * this.pxPerDay, 8);
      const y = this.headerH + i * this.rowH + (this.rowH - this.barH) / 2;
      return {
        id: t.id,
        name: t.name,
        phaseColorVar: this.phaseColorFor(t.phaseId),
        x, y, w, h: this.barH,
        progW: Math.round((w * t.progressPct) / 100),
        progressPct: t.progressPct,
        startsOn: t.startsOn,
        endsOn: t.endsOn,
      };
    });
  });

  readonly arrows = computed<Arrow[]>(() => {
    const byId = new Map(this.rows().map((r) => [r.id, r]));
    const out: Arrow[] = [];
    for (const t of this.tasks()) {
      if (!t.dependsOnTaskId) continue;
      const from = byId.get(t.dependsOnTaskId);
      const to = byId.get(t.id);
      if (!from || !to) continue;
      const x1 = from.x + from.w;
      const y1 = from.y + from.h / 2;
      const x2 = to.x;
      const y2 = to.y + to.h / 2;
      const midX = Math.max(x1 + 10, x2 - 12);
      out.push({ id: `${t.dependsOnTaskId}->${t.id}`, d: `M ${x1} ${y1} H ${midX} V ${y2} H ${x2 - 2}` });
    }
    return out;
  });

  readonly ticks = computed<Tick[]>(() => {
    const min = this.minDay();
    const max = this.maxDay();
    const out: Tick[] = [];
    // A tick every 14 days.
    for (let d = min; d <= max; d += 14) {
      const x = this.labelW + (d - min) * this.pxPerDay;
      const label = new Date(d * DAY).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
      out.push({ x, label });
    }
    return out;
  });

  constructor(public auth: AuthService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.route.parent?.paramMap.subscribe((p) => this.projectId.set(p.get('id') ?? ''));
  }

  // ---- Planner drag-to-set-progress ----
  onBarDown(evt: PointerEvent, row: Row): void {
    if (!this.auth.isPlanner()) return;
    (evt.target as Element).setPointerCapture?.(evt.pointerId);
    this.dragId = row.id;
    this.applyProgress(evt, row);
  }
  onBarMove(evt: PointerEvent, row: Row): void {
    if (this.dragId !== row.id) return;
    this.applyProgress(evt, row);
  }
  onBarUp(row: Row): void {
    if (this.dragId === row.id) {
      this.dragId = null;
      // service_agent: PATCH /tasks/:id/progress with row.progressPct here.
    }
  }

  private applyProgress(evt: PointerEvent, row: Row): void {
    const svg = (evt.currentTarget as SVGGraphicsElement).ownerSVGElement;
    if (!svg) return;
    const pt = svg.createSVGPoint();
    pt.x = evt.clientX;
    pt.y = evt.clientY;
    const ctm = svg.getScreenCTM();
    if (!ctm) return;
    const loc = pt.matrixTransform(ctm.inverse());
    const pct = Math.max(0, Math.min(100, Math.round(((loc.x - row.x) / row.w) * 100)));
    this.tasks.update((list) => list.map((t) => (t.id === row.id ? { ...t, progressPct: pct } : t)));
  }
}
